/**
 * hit-log.ts — Track usage of facts/wiki/skills via append-only JSONL.
 * Provides stats for factlint "zero-hit" reporting and grouped evaluation.
 */
import { appendFile, readFile } from "node:fs/promises";
import { readFileSync } from "node:fs";
import path from "node:path";
import { config } from "./config.js";

const LOG_FILE = path.join(config.memoryDir, "hit-log.jsonl");

export interface HitEntry {
  ts: string;
  type: "fact" | "wiki" | "skill" | "index";
  key: string;
  source: string;
}

/** Append a hit entry. Fire-and-forget (never throws). */
export function logHit(type: HitEntry["type"], key: string, source: string): void {
  const entry: HitEntry = { ts: new Date().toISOString(), type, key, source };
  appendFile(LOG_FILE, JSON.stringify(entry) + "\n").catch(() => {});
}

/** Read hit log and return stats for the last N days. */
export async function getHitStats(days = 30): Promise<Map<string, number>> {
  const cutoff = Date.now() - days * 86_400_000;
  const stats = new Map<string, number>();
  let raw: string;
  try {
    raw = await readFile(LOG_FILE, "utf8");
  } catch {
    return stats;
  }
  for (const line of raw.split("\n")) {
    if (!line.trim()) continue;
    try {
      const e: HitEntry = JSON.parse(line);
      if (new Date(e.ts).getTime() < cutoff) continue;
      const k = `${e.type}:${e.key}`;
      stats.set(k, (stats.get(k) ?? 0) + 1);
    } catch { /* skip malformed */ }
  }
  return stats;
}

// ─── Repo Health (Compression Metric) ────────────────────────────────────────

const ACTIONABLE_RE = /因為|避免|不要|不可|遇到.*要|必須|禁止|改用|換成|確保|注意/;

export interface RepoHealth {
  total: number;
  actionable: number;
  ratio: number;
}

/** Compute repo health: ratio of total facts to actionable (guidance-bearing) facts. */
export function computeRepoHealth(shards: Array<{ file: string }>): RepoHealth {
  let total = 0, actionable = 0;
  for (const s of shards) {
    let content: string;
    try { content = readFileSync(s.file, "utf8"); } catch { continue; }
    for (const line of content.split(/\r?\n/)) {
      if (!line.trim() || !line.startsWith("-")) continue;
      total++;
      if (ACTIONABLE_RE.test(line)) actionable++;
    }
  }
  return { total, actionable, ratio: actionable > 0 ? total / actionable : total };
}

