5	import { appendFile, readFile } from "node:fs/promises";
6	import { readFileSync } from "node:fs";
7	import path from "node:path";
8	import { config } from "./config.js";
9	
10	const LOG_FILE = path.join(config.memoryDir, "hit-log.jsonl");
11	
12	export interface HitEntry {
13	  ts: string;
14	  type: "fact" | "wiki" | "skill" | "index";
15	  key: string;
16	  source: string;
17	}
18	
19	/** Append a hit entry. Fire-and-forget (never throws). */
20	export function logHit(type: HitEntry["type"], key: string, source: string): void {
21	  const entry: HitEntry = { ts: new Date().toISOString(), type, key, source };
22	  appendFile(LOG_FILE, JSON.stringify(entry) + "\n").catch(() => {});
23	}
24	
25	/** Read hit log and return stats for the last N days. */
26	export async function getHitStats(days = 30): Promise<Map<string, number>> {
27	  const cutoff = Date.now() - days * 86_400_000;
28	  const stats = new Map<string, number>();
29	  let raw: string;
30	  try {
31	    raw = await readFile(LOG_FILE, "utf8");
32	  } catch {
33	    return stats;
34	  }
35	  for (const line of raw.split("\n")) {
36	    if (!line.trim()) continue;
37	    try {
38	      const e: HitEntry = JSON.parse(line);
39	      if (new Date(e.ts).getTime() < cutoff) continue;
40	      const k = `${e.type}:${e.key}`;
41	      stats.set(k, (stats.get(k) ?? 0) + 1);
42	    } catch { /* skip malformed */ }
43	  }
44	  return stats;
45	}
46	
47	// ─── Repo Health (Compression Metric) ────────────────────────────────────────
48	
49	const ACTIONABLE_RE = /因為|避免|不要|不可|遇到.*要|必須|禁止|改用|換成|確保|注意/;
50	
51	export interface RepoHealth {
52	  total: number;
53	  actionable: number;
54	  ratio: number;
55	}
56	
57	/** Compute repo health: ratio of total facts to actionable (guidance-bearing) facts. */
58	export function computeRepoHealth(shards: Array<{ file: string }>): RepoHealth {
59	  let total = 0, actionable = 0;
60	  for (const s of shards) {
61	    let content: string;
62	    try { content = readFileSync(s.file, "utf8"); } catch { continue; }
63	    for (const line of content.split(/\r?\n/)) {
64	      if (!line.trim() || !line.startsWith("-")) continue;
65	      total++;
66	      if (ACTIONABLE_RE.test(line)) actionable++;
67	    }
68	  }
69	  return { total, actionable, ratio: actionable > 0 ? total / actionable : total };
70	}
71	
