/**
 * memory-db.ts — SQLite derived index for facts.
 *
 * The master log (facts-<userId>.md) remains the source of truth.
 * This module maintains a SQLite DB as a derived search index with:
 *   - FTS5 full-text search (BM25)
 *   - Embedding cache (content hash → vector)
 *   - Temporal decay on retrieval
 *   - Precise content-hash dedup
 *
 * Delete the .db file and call syncFactsToDb() to rebuild from .md.
 */

import Database, { type Database as DatabaseType } from "better-sqlite3";
import { createHash } from "node:crypto";
import { readFileSync, existsSync } from "node:fs";
import path from "node:path";
import { resolveMemoryDir, masterFactsFile } from "./facts-store.js";
import { classifyFact } from "./topic-rules.js";
import { embedText, cosineSim } from "./embed-router.js";

// ─── Config ──────────────────────────────────────────────────────────────────

const DB_FILENAME = "memory-index.db";
const HALF_LIFE_DAYS = 30;
const LAMBDA = Math.LN2 / HALF_LIFE_DAYS;
const VECTOR_WEIGHT = 0.7;
const BM25_WEIGHT = 0.3;
const DEFAULT_THRESHOLD = 0.35;
const DEFAULT_TOP_K = 15;

/**
 * Source-tier boost: curated/structured topics get a score multiplier.
 * Inspired by GBrain's source-aware ranking where wiki > chat log.
 * Topics with wiki pages or lesson-grade content rank higher than misc/transient.
 */
const SOURCE_TIER_BOOST: Record<string, number> = {
  // Tier 1: architecture/design decisions (most curated)
  "bridge-arch": 1.3,
  "bridge-preamble": 1.3,
  "bridge-llm-hybrid": 1.3,
  "user-preference": 1.3,
  // Tier 2: established subsystems with wiki pages
  "bridge-token-protocol": 1.2,
  "bridge-embedding-router": 1.2,
  "bridge-goal-state": 1.2,
  "slot-codegen": 1.2,
  "cocos-editor": 1.2,
  "local-llm": 1.2,
  // Tier 3: default (no boost)
  // Tier 4: transient/catchall (slight penalty)
  "misc": 0.85,
};
const DEFAULT_TIER_BOOST = 1.0;

// ─── State ───────────────────────────────────────────────────────────────────

let db: DatabaseType | null = null;

// ─── Public API ──────────────────────────────────────────────────────────────

export function getDb(): DatabaseType | null {
  return db;
}

export function initMemoryDb(): void {
  const dbPath = path.join(resolveMemoryDir(), DB_FILENAME);
  db = new Database(dbPath);
  db.pragma("journal_mode = WAL");
  db.pragma("synchronous = NORMAL");
  createSchema(db);
}

export function closeMemoryDb(): void {
  db?.close();
  db = null;
}

/**
 * Sync master log → SQLite. Diff by content hash: insert new, delete removed.
 * Returns { inserted, deleted }.
 */
export function syncFactsToDb(userId: number | string): { inserted: number; deleted: number } {
  if (!db) return { inserted: 0, deleted: 0 };

  const masterPath = masterFactsFile(userId);
  const parsed = parseMasterLog(masterPath);

  // Get existing hashes in DB
  const existingRows = db.prepare("SELECT content_hash FROM facts").all() as Array<{ content_hash: string }>;
  const existingHashes = new Set(existingRows.map((r) => r.content_hash));
  const newHashes = new Set(parsed.map((f) => f.hash));

  // Delete facts no longer in master
  const toDelete = [...existingHashes].filter((h) => !newHashes.has(h));
  if (toDelete.length > 0) {
    const del = db.prepare("DELETE FROM facts WHERE content_hash = ?");
    const delFts = db.prepare("DELETE FROM facts_fts WHERE content_hash = ?");
    const tx = db.transaction(() => {
      for (const h of toDelete) {
        del.run(h);
        delFts.run(h);
      }
    });
    tx();
  }

  // Insert new facts
  const toInsert = parsed.filter((f) => !existingHashes.has(f.hash));
  if (toInsert.length > 0) {
    const ins = db.prepare(
      "INSERT OR IGNORE INTO facts (content_hash, text, topic, created_at) VALUES (?, ?, ?, ?)",
    );
    const insFts = db.prepare(
      "INSERT OR IGNORE INTO facts_fts (content_hash, text) VALUES (?, ?)",
    );
    const tx = db.transaction(() => {
      for (const f of toInsert) {
        ins.run(f.hash, f.text, f.topic, f.createdAt);
        insFts.run(f.hash, f.text);
      }
    });
    tx();
  }

  return { inserted: toInsert.length, deleted: toDelete.length };
}

/**
 * Insert a single fact (called after remember() writes to .md).
 */
export function insertFact(text: string, topic: string, createdAt: string): void {
  if (!db) return;
  const hash = contentHash(text);
  db.prepare("INSERT OR IGNORE INTO facts (content_hash, text, topic, created_at) VALUES (?, ?, ?, ?)").run(
    hash, text, topic, createdAt,
  );
  db.prepare("INSERT OR IGNORE INTO facts_fts (content_hash, text) VALUES (?, ?)").run(hash, text);
}

/**
 * Delete facts by content hash (called after forget()).
 */
export function deleteFact(text: string): void {
  if (!db) return;
  const hash = contentHash(text);
  db.prepare("DELETE FROM facts WHERE content_hash = ?").run(hash);
  db.prepare("DELETE FROM facts_fts WHERE content_hash = ?").run(hash);
}

/**
 * Check if a fact with the same content hash already exists.
 */
export function factExists(text: string): boolean {
  if (!db) return false;
  const hash = contentHash(text);
  const row = db.prepare("SELECT 1 FROM facts WHERE content_hash = ?").get(hash);
  return !!row;
}

// ─── Embedding Cache ─────────────────────────────────────────────────────────

/**
 * Get embedding for text, using cache. Returns null if embed router not ready.
 */
export async function getEmbeddingCached(text: string): Promise<Float32Array | null> {
  if (!db) return embedText(text);
  const hash = contentHash(text);

  // Cache hit
  const row = db.prepare("SELECT vector FROM embedding_cache WHERE content_hash = ?").get(hash) as
    | { vector: Buffer }
    | undefined;
  if (row) {
    return new Float32Array(row.vector.buffer, row.vector.byteOffset, row.vector.byteLength / 4);
  }

  // Cache miss — compute
  const vec = await embedText(text);
  if (vec) {
    const buf = Buffer.from(vec.buffer, vec.byteOffset, vec.byteLength);
    db.prepare("INSERT OR IGNORE INTO embedding_cache (content_hash, vector) VALUES (?, ?)").run(hash, buf);
  }
  return vec;
}

// ─── Hybrid Search ───────────────────────────────────────────────────────────

export interface HybridSearchOpts {
  topK?: number;
  threshold?: number;
  enableDecay?: boolean;
  /** Exclude facts already in preamble tail */
  excludeTexts?: Set<string>;
}

export interface HybridHit {
  text: string;
  topic: string;
  score: number;
  createdAt: string;
}

/**
 * Hybrid search: FTS5 BM25 + vector cosine, merged with temporal decay.
 */
export async function hybridSearch(query: string, opts: HybridSearchOpts = {}): Promise<HybridHit[]> {
  if (!db) return [];
  const topK = opts.topK ?? DEFAULT_TOP_K;
  const threshold = opts.threshold ?? DEFAULT_THRESHOLD;
  const enableDecay = opts.enableDecay ?? true;

  const queryVec = await getEmbeddingCached(query);

  // 1. FTS5 BM25 results
  const bm25Hits = fts5Search(query);

  // 2. Vector cosine results (brute-force over all facts with cached embeddings)
  const vectorHits = queryVec ? await vectorSearch(queryVec) : [];

  // 3. Merge scores
  const scoreMap = new Map<string, { text: string; topic: string; createdAt: string; bm25: number; vector: number }>();

  for (const h of bm25Hits) {
    scoreMap.set(h.hash, { text: h.text, topic: h.topic, createdAt: h.createdAt, bm25: h.score, vector: 0 });
  }
  for (const h of vectorHits) {
    const existing = scoreMap.get(h.hash);
    if (existing) {
      existing.vector = h.score;
    } else {
      scoreMap.set(h.hash, { text: h.text, topic: h.topic, createdAt: h.createdAt, bm25: 0, vector: h.score });
    }
  }

  // 4. Compute final score with decay
  const now = Date.now();
  const results: HybridHit[] = [];

  for (const [, entry] of scoreMap) {
    if (opts.excludeTexts?.has(entry.text)) continue;

    let score = VECTOR_WEIGHT * entry.vector + BM25_WEIGHT * entry.bm25;

    // Source-tier boost: curated topics rank higher
    const tierBoost = SOURCE_TIER_BOOST[entry.topic] ?? DEFAULT_TIER_BOOST;
    score *= tierBoost;

    // Temporal decay
    if (enableDecay && entry.createdAt) {
      const ageDays = (now - new Date(entry.createdAt).getTime()) / 86_400_000;
      if (ageDays > 0) {
        score *= Math.exp(-LAMBDA * ageDays);
      }
    }

    if (score >= threshold) {
      results.push({ text: entry.text, topic: entry.topic, score, createdAt: entry.createdAt });
    }
  }

  results.sort((a, b) => b.score - a.score);
  return results.slice(0, topK);
}

// ─── Internals ───────────────────────────────────────────────────────────────

function createSchema(database: DatabaseType): void {
  database.exec(`
    CREATE TABLE IF NOT EXISTS facts (
      content_hash TEXT PRIMARY KEY,
      text TEXT NOT NULL,
      topic TEXT NOT NULL DEFAULT 'misc',
      created_at TEXT NOT NULL DEFAULT ''
    );
    CREATE TABLE IF NOT EXISTS embedding_cache (
      content_hash TEXT PRIMARY KEY,
      vector BLOB NOT NULL
    );
    CREATE VIRTUAL TABLE IF NOT EXISTS facts_fts USING fts5(
      content_hash UNINDEXED,
      text,
      tokenize='unicode61'
    );
  `);
}

export function contentHash(text: string): string {
  return createHash("sha256").update(text.trim()).digest("hex").slice(0, 16);
}

interface ParsedFact {
  text: string;
  hash: string;
  topic: string;
  createdAt: string;
}

function parseMasterLog(filePath: string): ParsedFact[] {
  if (!existsSync(filePath)) return [];
  const raw = readFileSync(filePath, "utf8");
  const results: ParsedFact[] = [];
  for (const line of raw.split(/\r?\n/)) {
    // Format: "- [2026-05-16T10:00:00.000Z] fact text here"
    const match = line.match(/^\s*-\s*\[([^\]]+)\]\s*(.+)$/);
    if (!match) continue;
    const createdAt = match[1];
    const text = match[2].trim();
    if (!text) continue;
    const topic = classifyFact(text) || "misc";
    results.push({ text, hash: contentHash(text), topic, createdAt });
  }
  return results;
}

interface FtsHit {
  hash: string;
  text: string;
  topic: string;
  createdAt: string;
  score: number;
}

function fts5Search(query: string): FtsHit[] {
  if (!db) return [];
  // Escape FTS5 special chars and build a simple query
  const escaped = query.replace(/['"*(){}[\]^~\\:]/g, " ").trim();
  if (!escaped) return [];
  try {
    const rows = db
      .prepare(
        `SELECT f.content_hash as hash, f.text, f.topic, f.created_at as createdAt,
                rank * -1 as score
         FROM facts_fts fts
         JOIN facts f ON f.content_hash = fts.content_hash
         WHERE facts_fts MATCH ?
         ORDER BY rank
         LIMIT 50`,
      )
      .all(escaped) as FtsHit[];

    // Normalize BM25 scores to 0-1 range
    if (rows.length === 0) return [];
    const maxScore = Math.max(...rows.map((r) => r.score), 1);
    return rows.map((r) => ({ ...r, score: r.score / maxScore }));
  } catch {
    // FTS5 match can throw on malformed queries
    return [];
  }
}

interface VectorHit {
  hash: string;
  text: string;
  topic: string;
  createdAt: string;
  score: number;
}

async function vectorSearch(queryVec: Float32Array): Promise<VectorHit[]> {
  if (!db) return [];
  // Get all facts that have cached embeddings
  const rows = db
    .prepare(
      `SELECT f.content_hash as hash, f.text, f.topic, f.created_at as createdAt, ec.vector
       FROM facts f
       JOIN embedding_cache ec ON ec.content_hash = f.content_hash`,
    )
    .all() as Array<{ hash: string; text: string; topic: string; createdAt: string; vector: Buffer }>;

  const hits: VectorHit[] = [];
  for (const row of rows) {
    const vec = new Float32Array(row.vector.buffer, row.vector.byteOffset, row.vector.byteLength / 4);
    const score = cosineSim(queryVec, vec);
    if (score > 0.1) {
      hits.push({ hash: row.hash, text: row.text, topic: row.topic, createdAt: row.createdAt, score });
    }
  }
  return hits;
}

