 */
export function insertFact(text: string, topic: string, createdAt: string): void {
  if (!db) return;
  const hash = contentHash(text);
  db.prepare("INSERT OR IGNORE INTO facts (content_hash, text, topic, created_at) VALUES (?, ?, ?, ?)").run(
    hash, text, topic, createdAt,
  );
  db.prepare("INSERT OR IGNORE INTO facts_fts (content_hash, text) VALUES (?, ?)").run(hash, text);
  // 補嵌入（fire-and-forget）：model 未就緒時回 null 不寫 cache，由下次啟動 backfill 補
  void getEmbeddingCached(text).catch(() => {});
}

/**
 * Backfill embeddings for facts missing from embedding_cache.
 * 冪等、只補缺；vectorSearch 的 JOIN 依賴 fact 文字有嵌入，缺了 vector 分量恆 0。
 * Returns the number of facts backfilled.
 */
export async function backfillFactEmbeddings(): Promise<number> {
  if (!db) return 0;
  const missing = db
    .prepare(
      `SELECT f.text FROM facts f
       LEFT JOIN embedding_cache ec ON ec.content_hash = f.content_hash
       WHERE ec.content_hash IS NULL`,
    )
    .all() as Array<{ text: string }>;
  let done = 0;
  for (const { text } of missing) {
    const vec = await getEmbeddingCached(text);
    if (vec) done++;
  }
  return done;
}

