export async function handleFactLint(ctx: Context): Promise<void> {
  const { isAllowed, sessions, runPrompt } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  let session;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}\n` +
        `Check that 'kiro-cli' is installed and on PATH.`,
    );
    return;
  }

  // Pre-scan ALL shards with local LLM for dedup hints (best-effort)
  let dedupHint = "";
  try {
    const userId = ctx.from?.id;
    if (userId) {
      const shardInfos = listTopicShards(userId);
      const shards = shardInfos.map(s => ({
        topic: s.topic,
        facts: readFileSync(s.file, "utf8").split(/\r?\n/).filter(l => l.trim()),
      }));
      const issues = await detectAllShardDuplicates(shards);
      if (issues.length > 0) {
        const lines = issues.map(
          iss => `  - [${iss.topic}] ${iss.type.toUpperCase()}: "${iss.factA.slice(0, 60)}" vs "${iss.factB.slice(0, 60)}" — ${iss.reason}`
        );
        dedupHint = `\n\n[Local LLM pre-scan detected ${issues.length} potential issue(s) across shards — verify and act on these first]\n${lines.join("\n")}\n`;
      }
    }
  } catch { /* Ollama unavailable — skip pre-scan */ }

  // Merge/upgrade suggestions from local LLM (optional)
  let mergeHint = "";
  try {
    const userId = ctx.from?.id;
    if (userId) {
      const shardInfos = listTopicShards(userId);
      const bigShards = shardInfos.filter(s => s.count >= 5);
      const allSuggestions: string[] = [];
      for (const s of bigShards.slice(0, 5)) {
        const facts = readFileSync(s.file, "utf8").split(/\r?\n/).filter(l => l.trim());
        const suggestions = await suggestFactMerges(s.topic, facts);
        for (const sg of suggestions) {
          allSuggestions.push(`  - [${s.topic}] 合併 #${sg.indices.join(",")} → "${sg.merged}"`);
        }
      }
      if (allSuggestions.length > 0) {
        mergeHint = `\n\n[升格建議 — Local LLM 建議以下 facts 可合併精煉（僅供參考，不自動執行）]\n${allSuggestions.join("\n")}\n`;
      }
    }
  } catch { /* Ollama unavailable — skip */ }

  // Hit log stats: zero-hit topics + repo health
  let hitHint = "";
  try {
    const userId = ctx.from?.id;
    if (userId) {
      const stats = await getHitStats(30);
      const shardInfos = listTopicShards(userId);
      const allTopics = shardInfos.map(s => s.topic);
      const zeroHit = allTopics.filter(t => !stats.has(`fact:${t}`));
      if (zeroHit.length > 0) {
        hitHint += `\n\n[零命中區 — 以下 topic shards 過去 30 天未被任何 embedding recall 命中]\n${zeroHit.map(t => `  - ${t}`).join("\n")}\n對這些 shard 的 facts 額外留意是否已過時或描述不夠好。\n`;
      }
      const health = computeRepoHealth(shardInfos);
      if (health.ratio > 3.0) {
        hitHint += `\n[⚠️ Repo 膨脹警告] total=${health.total}, actionable=${health.actionable}, ratio=${health.ratio.toFixed(1)} (>3.0)\n建議清理純記錄性 facts（不含指引語的）。\n`;
      }
    }
  } catch { /* hit-log not yet populated — skip */ }

  await runPrompt(ctx, session, FACTLINT_PROMPT + dedupHint + mergeHint + hitHint, { kind: "meta" });
}


// ─── /wikilint ──────────────────────────────────────────────────────────────

const WIKILINT_PROMPT =
  "請執行 wiki lint（wiki 健康檢查）：\n" +
  "1. 讀 `${MEMORY_DIR}/wiki/index.md` 取得所有 wiki page 列表。\n" +
  "2. 對每個 wiki page 執行以下檢查：\n" +
  "   - **過時偵測**：讀頁面的 `updated` 日期，再讀對應 topic shard（用 list_facts）比對最新 facts。若 shard 有明顯更新的資訊但 wiki page 未反映，標記為 stale。\n" +
  "   - **孤兒頁面**：index.md 列出但檔案不存在，或檔案存在但 index.md 未列出。\n" +
  "   - **斷連 wikilink**：頁面內的 `[[wikilink]]` 指向不存在的 slug。\n" +
  "3. 回報格式：\n" +
  "   - 🟢 健康頁面數量\n" +
  "   - 🟡 Stale（列出 slug + updated 日期 + 需更新的原因）\n" +
  "   - 👻 Orphans（列出 slug + 問題描述）\n" +
  "   - 🔗 Broken links（列出來源頁面 + 斷連的 [[target]]）\n" +
  "   - 建議動作（更新/刪除/補連結）\n" +
  "4. 若 stale 頁面的更新內容明確，直接更新頁面並 bump `updated` 日期。其餘只列報告。\n" +
  "用繁體中文回報。\n" +
  "回覆末尾加上：<<SKILL_USED:ms-wiki-knowledge-base|wikilint 步驟>>";

export async function handleWikiLint(ctx: Context): Promise<void> {
  const { isAllowed, sessions, runPrompt } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  let session;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}\n` +
        `Check that 'kiro-cli' is installed and on PATH.`,
    );
    return;
  }
  await runPrompt(ctx, session, WIKILINT_PROMPT, { kind: "meta" });
}

// ─── /skilllint ─────────────────────────────────────────────────────────────

const SKILLLINT_PROMPT =
  "請執行 skill lint（技能健康檢查）：\n" +
  "1. 讀 `${MEMORY_DIR}/config/skill-usage.json` 取得所有 skill 的使用紀錄（use_count, last_agent_used_at, orphan, pinned）。\n" +
  "2. 列出 `${SKILL_DIR}/` 底下所有 skill 資料夾名稱。\n" +
  "3. 對每個 skill 執行以下檢查：\n" +
  "   - **過時偵測**：讀 SKILL.md 內容，比對 facts（呼叫 list_facts 相關 topic）看是否有矛盾的路徑/API/做法/架構描述。若 skill 描述的做法已被 facts 記錄的新決策取代，標記為 stale。\n" +
  "   - **使用頻率**：從 skill-usage.json 的 use_count 和 last_agent_used_at 判斷。超過 30 天未被使用且 use_count < 3 的標記為 underused。\n" +
  "   - **衝突偵測**：兩個 skill 的觸發情境（description）語意高度重疊但建議做法不同，標記為 conflict。\n" +
  "   - **孤兒清理**：skill-usage.json 中 orphan=true 的（SKILL.md 已不存在）列出。\n" +
  "4. 回報格式：\n" +
  "   - 🟢 健康 skill 數量\n" +
  "   - 🟡 Underused（列出名稱 + 上次使用時間 + use_count）\n" +
  "   - 🔴 Stale（列出名稱 + 矛盾點）\n" +
  "   - ⚠️ Conflicts（列出衝突對 + 原因）\n" +
  "   - 👻 Orphans（列出名稱）\n" +
  "   - 建議動作（刪除/合併/更新）\n" +
  "5. pinned=true 的 skill 跳過 underused 檢查（使用者明確保留）。\n" +
  "不要自動刪除任何 skill，只列報告。用繁體中文回報。";

export async function handleSkillLint(ctx: Context): Promise<void> {
  const { isAllowed, sessions, runPrompt } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  let session;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}\n` +
        `Check that 'kiro-cli' is installed and on PATH.`,
    );
    return;
  }
  await runPrompt(ctx, session, SKILLLINT_PROMPT, { kind: "meta" });
}

// ─── /specialistreview ──────────────────────────────────────────────────────

export async function handleSpecialistReview(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  const notice = await ctx.reply("🔍 分析 topic clusters…");
  try {
    const userId = ctx.from?.id ?? chatId;
    const result = await runSpecialistReview(userId);
    if (result.expansions.length > 0) {
      await applyExpansions(result.expansions);
    }
    const report = formatReviewReport(result);
    await ctx.api.editMessageText(chatId, notice.message_id, report);
  } catch (err: any) {
    await ctx.api.editMessageText(chatId, notice.message_id, `❌ specialist-review 失敗：${err.message}`);
  }
}

// ─── /specialist ────────────────────────────────────────────────────────────

export async function handleSpecialist(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;
  const arg = (ctx.match as string | undefined)?.trim() ?? "";
  const parts = arg.split(/\s+/);

  // No arg → show inline keyboard to pick a specialist for proxy
  if (!arg || (parts[0] !== "create" && !isLocalSpecialist(arg))) {
    const specialists = getSpecialists();
    if (specialists.length === 0) {
      await ctx.reply("目前沒有可用的分身。用 /specialist create <name> 建立。");
      return;
    }
    const kb = new InlineKeyboard();
    for (const s of specialists) {
      kb.text(`🤖 ${s.name}`, `specialist:${s.name}`).row();
    }
    await ctx.reply("選擇分身進入 proxy：", { reply_markup: kb });
    return;
  }

  if (parts[0] !== "create" || !parts[1]) {
    await ctx.reply("用法：/specialist create <name>");
    return;
  }

  const name = parts[1].toLowerCase();
  const notice = await ctx.reply(`🤖 分析 specialist "${name}" 的 skill 組合…`);

  try {
    const analysis = await analyzeForSpecialist(name);
    const result = await generateSpecialistConfig(analysis);

    const lines = [
      `✅ Specialist "${name}" 配置已產生：`,
      ``,
      `📄 Agent config: \`${result.agentConfigPath}\``,
      `📄 Specialists: \`${result.specialistsJsonPath}\``,
      ``,
      `🧩 Skills (${result.skills.length}):`,
      ...result.skills.map((s) => `  • ${s}`),
      ``,
      `🔌 MCP servers: ${result.mcpServers.length ? result.mcpServers.join(", ") : "(none)"}`,
      ``,
      `🏷️ Related topics (${analysis.relevantTopics.length}):`,
      ...analysis.relevantTopics.slice(0, 10).map((t) => `  • ${t}`),
      ``,
      `⚠️ 需要 /restart 才會載入新配置。`,
    ];

    await ctx.api.editMessageText(ctx.chat!.id, notice.message_id, lines.join("\n"));
  } catch (err: any) {
    await ctx.api.editMessageText(
      ctx.chat!.id,
      notice.message_id,
      `❌ 失敗：${err.message}`,
    );
  }
}

